import numpy as np
from collections import deque

class SimpleKG:
    def __init__(self):
        self._g = {}
    def add(self, s, r, o):
        self._g.setdefault(s, []).append((r, o))
    def neighbors(self, e):
        return self._g.get(e, [])

kg = SimpleKG()
kg.add('A', 'r', 'B')
# C is semantically close to query but not in graph
np.random.seed(0)
embeds = {
    'A': np.array([1.,0.,0.]),
    'B': np.array([0.9,0.1,0.]),
    'C': np.array([0.,0.,-1.])
}
result = hybrid_kg_retrieval(kg, embeds, 'A', np.array([1.,0.,0.]), top_k=2, n_hops=1)
assert 'B' in result, 'Graph-adjacent B should be in top-2'

